// Eingabe validieren
const body = $input.first().json;

if (!body.tenant_slug) throw new Error('tenant_slug fehlt');
if (!body.name) throw new Error('name fehlt');
if (!body.source_type) body.source_type = 'file';

if (!['file', 'url', 'manual'].includes(body.source_type)) {
  throw new Error('source_type muss file, url oder manual sein');
}

if (body.source_type === 'file' && !body.file_base64) {
  throw new Error('file_base64 fehlt bei source_type=file');
}

return [{ json: {
  tenant_slug: body.tenant_slug,
  name: body.name,
  source_type: body.source_type,
  file_base64: body.file_base64 || null,
  file_name: body.file_name || body.name,
  file_type: body.file_type || 'pdf',
  origin_url: body.origin_url || null,
  tags: body.tags || [],
  doc_type: body.doc_type || 'general',
  manual_text: body.manual_text || null
}}];

const rows = $input.all().map(i => i.json);
const tenant = rows[0];
if (!tenant || !tenant.id) {
  throw new Error('Tenant nicht gefunden oder nicht aktiv: ' + $('Validate Input').first().json.tenant_slug);
}
const input = $('Validate Input').first().json;
return [{ json: { ...input, tenant_id: tenant.id, tenant_name: tenant.name } }];

const sourceRow = $input.first().json;
const prev = $('Check Tenant Exists').first().json;
return [{ json: { ...prev, source_id: sourceRow.id } }];

// Text-Extraktion
const item = $input.first().json;
const fileType = item.file_type || 'txt';
let extractedText = '';

if (item.source_type === 'manual' && item.manual_text) {
  extractedText = item.manual_text;
} else if (fileType === 'txt' || fileType === 'md') {
  extractedText = Buffer.from(item.file_base64 || '', 'base64').toString('utf-8');
} else if (fileType === 'html') {
  const raw = Buffer.from(item.file_base64 || '', 'base64').toString('utf-8');
  extractedText = raw
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/\s+/g, ' ')
    .trim();
} else if (fileType === 'pdf') {
  // PDF: Versuche Text aus base64 zu extrahieren
  // Fuer echte PDF-Extraktion: n8n 'Extract From File' Node vorschalten
  // oder pdftotext Service nutzen
  const raw = Buffer.from(item.file_base64 || '', 'base64').toString('utf-8');
  // Einfache Heuristik: Suche lesbaren Text zwischen PDF-Markern
  extractedText = raw
    .replace(/[^\x20-\x7E\xC0-\xFF\n]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  // Falls kein sinnvoller Text gefunden
  if (extractedText.length < 50) {
    throw new Error('PDF-Text konnte nicht extrahiert werden. Nutze den n8n "Extract From File" Node oder lade Text manuell hoch (source_type=manual, manual_text=...).');
  }
}

if (!extractedText || extractedText.length < 10) {
  throw new Error('Kein Text extrahiert — Datei leer oder Format nicht unterstuetzt');
}

// file_base64 entfernen um Speicher zu sparen
const { file_base64, ...rest } = item;
return [{ json: { ...rest, extracted_text: extractedText, char_count: extractedText.length } }];

const docRow = $input.first().json;
const prev = $('Extract Text').first().json;
return [{ json: { ...prev, document_id: docRow.id } }];

// Text in Chunks aufteilen
const CHUNK_SIZE = 1000;
const CHUNK_OVERLAP = 150;

function chunkText(text, size, overlap) {
  const chunks = [];
  let start = 0;
  let index = 0;
  text = text.replace(/\r\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
  while (start < text.length) {
    let end = start + size;
    if (end < text.length) {
      const lastPeriod = text.lastIndexOf('.', end);
      const lastNewline = text.lastIndexOf('\n', end);
      const boundary = Math.max(lastPeriod, lastNewline);
      if (boundary > start + size * 0.5) end = boundary + 1;
    }
    const content = text.substring(start, Math.min(end, text.length)).trim();
    if (content.length > 50) {
      chunks.push({ chunk_index: index, content, char_count: content.length });
      index++;
    }
    start = end - overlap;
    if (start <= 0 && index > 0) break;
    if (start >= text.length) break;
  }
  return chunks;
}

const item = $input.first().json;
const chunks = chunkText(item.extracted_text, CHUNK_SIZE, CHUNK_OVERLAP);

return chunks.map(chunk => ({
  json: {
    tenant_id: item.tenant_id,
    source_id: item.source_id,
    document_id: item.document_id,
    name: item.name,
    tenant_slug: item.tenant_slug,
    ...chunk,
    total_chunks: chunks.length
  }
}));

const chunkRow = $input.first().json;
const prev = $('Chunk Text').item;
return [{ json: { ...prev.json, chunk_db_id: chunkRow.id } }];

const embResponse = $input.first().json;
const prev = $('Merge Chunk ID').first().json;

const embedding = embResponse.embedding;
if (!embedding || !Array.isArray(embedding)) {
  throw new Error('Embedding nicht erhalten von Ollama');
}

return [{ json: {
  ...prev,
  embedding: JSON.stringify(embedding),
  embedding_dims: embedding.length
}}];
